  ('aboriginal-57f41407-moex-00132', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '提起上訴之法定期間為幾日？', '["10日", "20日", "30日", "無期間限制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00133', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '下列何者「不屬於」得獨立為被告或犯罪嫌疑人選任辯護人之人？', '["被告或犯罪嫌疑人之法定代理人", "被告或犯罪嫌疑人之配偶", "被告或犯罪嫌疑人之家長或家屬", "被告或犯罪嫌疑人五親等外之旁系血親"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00134', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '下列關於要式行為的敘述，何者錯誤？', '["羈押被告，應用押票", "傳喚被告，應用傳票", "通緝證人，應用通緝書", "現行犯，不問何人都可以逕行逮捕"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00135', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於羈押敘述，下列何者正確？', '["憲法第8條第2項規定：「人民因犯罪嫌疑被逮捕拘禁時，……並至遲於24小時內移送該管『法院 審問』。」依司法院釋字第392號解釋，所指「法院審問」也包括檢察官之訊問在內", "辯護人或被告於偵查中之羈押審查程序，均得檢閱卷宗並得抄錄或攝影，不受任何限制", "不論是偵查中、審判中之羈押，或延長羈押，均以經法院訊問被告為必要", "被告或犯罪嫌疑人如經法院羈押，就表示日後一定會起訴並判決有罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00136', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '甲涉犯擄人勒贖罪嫌，由司法警察逮捕移送檢察官訊問後，認有羈押之必要，下列敘述何者正確？', '["法官不可僅以被告所犯為死刑、無期徒刑或最輕本刑為5年以上有期徒刑之罪，認為有羈押理由裁 定羈押", "偵查中羈押期間最長得羈押5個月", "僅須經過法官訊問、而有羈押原因、必要之條件，縱然無犯罪嫌疑重大，亦可裁定羈押", "被告之友人得隨時具保，向法院聲請停止羈押"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00137', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於送交現行犯之敘述，下列何者錯誤？', '["無偵查犯罪權限之人逮捕現行犯後，應即送交司法警察", "無偵查犯罪權限之人逮捕現行犯後，應即送交司法警察官", "無偵查犯罪權限之人逮捕現行犯後，應即送交檢察官", "無偵查犯罪權限之人逮捕現行犯後，應即送交司法事務官"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00138', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '依刑事訴訟法規定，當事人聲請調查之證據，法院認為不必要者，得以裁定駁回之。下列何者非屬不 必要？', '["不能調查", "待證事實已臻明瞭無再調查之必要", "同一證據再行聲請", "證人在國外工作，1個月後才能返國"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00139', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於法庭進行通常審判程序之證據調查，下列敘述何者錯誤？', '["證物應用提示、使其辨認之方式為之", "筆錄應用宣讀或告以要旨之方式為之", "得為證據之被告自白，應第一優先調查，其順位要在所有證據調查之前", "證人採用交互詰問之證據調查方式為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00140', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '在進行「反詰問」時，下列何種詰問依法得對證人為之？', '["誘導詰問", "抽象不明確之詰問", "就證人未親身經歷之事項詰問", "以利誘之方法詰問"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00141', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於法定證據方法之敘述，下列何者錯誤？', '["鑑定人除由審判長、受命法官或檢察官依法選任外，亦得由被告自行委任。被告自行委任之鑑定人 所出具之報告，如鑑定人確具專業能力，亦有證據能力", "鑑定人具有替代性，與證人不具替代性不同，因此不得拘提鑑定人", "檢察官、法院均得行勘驗。如係檢察官行勘驗，如有必要，得通知當事人、代理人或辯護人到場； 如係法院行勘驗，則應通知當事人、代理人或辯護人到場", "勘驗應記載勘驗筆錄，載明時、地，並由行勘驗之公務員簽名"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
